SELECT 'item1_bolt_8mm' AS item_key, sku, path FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='HECO 3DW-64B' AND name='Nut Bolt and Washer' AND json_extract(properties,'$.fastener_type')='bolt' AND json_extract(properties,'$.diameter')='8 mm' LIMIT 5;
SELECT 'item2_tool_bag' AS item_key, sku, path FROM products WHERE brand='Festool' AND series='Festool Stackable' AND model='SYS 3JJ-9LM' AND name='Tool Box and Bag' AND json_extract(properties,'$.storage_type')='tool bag' LIMIT 5;
SELECT 'item3_drywall_screw' AS item_key, sku, path FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='TopFix GTU-YPJ' AND name='Wood and Drywall Screw' AND json_extract(properties,'$.screw_type')='drywall screw' LIMIT 5;
SELECT 'item4_parts_case' AS item_key, sku, path FROM products WHERE brand='Festool' AND series='Festool Stackable' AND model='SYS 3JJ-9LM' AND name='Tool Box and Bag' AND json_extract(properties,'$.storage_type')='parts case' LIMIT 5;
SELECT 'item5_threaded_rod' AS item_key, sku, path FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='HECO 3DW-64B' AND name='Nut Bolt and Washer' AND json_extract(properties,'$.fastener_type')='threaded rod' LIMIT 5;

SELECT p.sku, p.path, p.brand, p.series, p.model, p.name FROM products p WHERE p.brand='Ajax' AND p.series='Ajax Concentrate Fresh' AND p.model='252-QRO' AND p.name='Cleaning Liquid' AND json_extract(p.properties,'$.cleaner_type')='floor cleaner' LIMIT 10;

SELECT s.store_id, s.name, s.city FROM stores s WHERE s.city='Vienna' ORDER BY s.store_id;

SELECT s.store_id, s.name, COALESCE(i.available_today,0) AS available_today FROM stores s LEFT JOIN inventory i ON i.store_id=s.store_id AND i.sku=(SELECT p2.sku FROM products p2 WHERE p2.brand='Ajax' AND p2.series='Ajax Concentrate Fresh' AND p2.model='252-QRO' AND p2.name='Cleaning Liquid' AND json_extract(p2.properties,'$.cleaner_type')='floor cleaner' LIMIT 1) WHERE s.city='Vienna' ORDER BY s.store_id;

SELECT p.sku, p.path FROM products p WHERE p.brand='Ajax' AND p.series='Ajax Concentrate Fresh' AND p.model='252-QRO' AND p.name='Cleaning Liquid' AND json_extract(p.properties,'$.cleaner_type')='floor cleaner' LIMIT 10;
SELECT s.id, s.path, s.name FROM stores s WHERE s.city='Vienna' ORDER BY s.id;
SELECT s.id, s.path, s.name, COALESCE(i.available_today,0) AS available_today FROM stores s LEFT JOIN inventory i ON i.store_id=s.id AND i.sku=(SELECT p2.sku FROM products p2 WHERE p2.brand='Ajax' AND p2.series='Ajax Concentrate Fresh' AND p2.model='252-QRO' AND p2.name='Cleaning Liquid' AND json_extract(p2.properties,'$.cleaner_type')='floor cleaner' LIMIT 1) WHERE s.city='Vienna' ORDER BY s.id;
SELECT COALESCE(SUM(COALESCE(i.available_today,0)),0) AS total_available_today FROM stores s LEFT JOIN inventory i ON i.store_id=s.id AND i.sku=(SELECT p2.sku FROM products p2 WHERE p2.brand='Ajax' AND p2.series='Ajax Concentrate Fresh' AND p2.model='252-QRO' AND p2.name='Cleaning Liquid' AND json_extract(p2.properties,'$.cleaner_type')='floor cleaner' LIMIT 1) WHERE s.city='Vienna';
